/**
 * @param {unknown} value
 * @returns {boolean}
 */
function isPlainObject(value) {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

/**
 * Invert object keys and values.
 * @param {Record<string, unknown>} source
 * @returns {Record<string, unknown>}
 * @throws {TypeError} When source is not a plain object
 */
export function invertObject(source) {
  if (!isPlainObject(source)) {
    throw new TypeError('source must be a plain object');
  }

  const inverted = {};
  for (const [key, value] of Object.entries(source)) {
    const invertedKey = String(value);
    const existing = inverted[invertedKey];
    if (existing === undefined) {
      inverted[invertedKey] = key;
    } else if (Array.isArray(existing)) {
      existing.push(key);
    } else {
      inverted[invertedKey] = [existing, key];
    }
  }
  return inverted;
}
